const express = require('express');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');

const app = express();

// --- Security Middleware ---

// Set secure HTTP headers
app.use(helmet());

// Parse JSON bodies with a size limit to prevent payload attacks
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// Rate limiting: max 100 requests per 15 minutes per IP
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// --- Routes ---

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res, next) => {
  try {
    // Validate optional query params (e.g., ?id=1)
    const { id } = req.query;
    if (id !== undefined) {
      const parsed = parseInt(id, 10);
      if (isNaN(parsed) || parsed <= 0) {
        return res.status(400).json({ error: 'Invalid id parameter. Must be a positive integer.' });
      }
    }

    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    const result = id ? users.filter(u => u.id === parseInt(id, 10)) : users;
    res.json(result);
  } catch (err) {
    next(err); // Forward to error handler
  }
});

// --- 404 Handler ---
app.use((req, res) => {
  res.status(404).json({ error: 'Route not found' });
});

// --- Centralized Error Handler ---
// eslint-disable-next-line no-unused-vars
app.use((err, req, res, next) => {
  console.error(err.stack); // Log full error server-side only

  // Never expose internal error details to the client
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error'
      : err.message, // Show details only in dev
  });
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});

module.exports = app;
```

